#include <bits/stdc++.h>
using namespace std;
unordered_map<int,int> h,l;
int sh,sl;
int main(){
    int n,k;
    scanf("%d%d",&n,&k);
    for(int i=1;i<=k;i++){
        int r,c;
        scanf("%d%d",&r,&c);
        if(!h[r])
            h[r]++,sh++;
        if(!l[c])
            l[c]++,sl++;
    }
    printf("%lld",1LL*n*sh+1LL*n*sl-1LL*sh*sl);
    return 0;
}
